/**
 * Centralized API client for consistent request/response handling
 * Handles authentication, error handling, and retry logic
 */
export class ApiClient {
    constructor(baseUrl = '') {
        Object.defineProperty(this, "baseUrl", {
            enumerable: true,
            configurable: true,
            writable: true,
            value: void 0
        });
        Object.defineProperty(this, "maxRetries", {
            enumerable: true,
            configurable: true,
            writable: true,
            value: 3
        });
        Object.defineProperty(this, "retryDelay", {
            enumerable: true,
            configurable: true,
            writable: true,
            value: 1000
        }); // Base delay in ms
        // Use relative URLs by default - nginx proxies /api/ to the backend
        // This works in both local dev (with proxy) and k8s (with nginx)
        this.baseUrl = baseUrl;
    }
    /**
     * Get authentication token from localStorage
     */
    getAuthToken() {
        return localStorage.getItem('auth_token');
    }
    /**
     * Set authentication token in localStorage
     */
    setAuthToken(token) {
        localStorage.setItem('auth_token', token);
    }
    /**
     * Clear authentication token
     */
    clearAuthToken() {
        localStorage.removeItem('auth_token');
    }
    /**
     * Create request headers with authentication
     */
    createHeaders(includeAuth = true) {
        const headers = {
            'Content-Type': 'application/json',
        };
        if (includeAuth) {
            const token = this.getAuthToken();
            if (token) {
                headers['Authorization'] = `Bearer ${token}`;
            }
        }
        return headers;
    }
    /**
     * Handle API response and extract data
     */
    async handleResponse(response) {
        const contentType = response.headers.get('content-type');
        let data;
        if (contentType && contentType.includes('application/json')) {
            data = await response.json();
        }
        else {
            data = { message: await response.text() };
        }
        // If response has the expected format, return it
        if (typeof data === 'object' && data !== null && 'success' in data) {
            return data;
        }
        // Handle non-standard responses
        if (response.ok) {
            return {
                success: true,
                data: data,
                timestamp: new Date().toISOString(),
            };
        }
        else {
            return {
                success: false,
                message: data.message || `HTTP ${response.status}: ${response.statusText}`,
                error_code: `HTTP_${response.status}`,
                timestamp: new Date().toISOString(),
            };
        }
    }
    /**
     * Retry logic with exponential backoff
     */
    async withRetry(operation, retries = this.maxRetries) {
        let lastError = null;
        for (let attempt = 0; attempt <= retries; attempt++) {
            try {
                const response = await operation();
                // Don't retry on authentication errors or client errors (4xx)
                if (response.status === 401 || response.status === 403 ||
                    (response.status >= 400 && response.status < 500)) {
                    return this.handleResponse(response);
                }
                // Don't retry on success
                if (response.ok) {
                    return this.handleResponse(response);
                }
                // Retry on server errors (5xx) or network issues
                if (attempt < retries) {
                    const delay = this.retryDelay * Math.pow(2, attempt);
                    await new Promise(resolve => setTimeout(resolve, delay));
                    continue;
                }
                return this.handleResponse(response);
            }
            catch (error) {
                lastError = error;
                if (attempt < retries) {
                    const delay = this.retryDelay * Math.pow(2, attempt);
                    await new Promise(resolve => setTimeout(resolve, delay));
                    continue;
                }
            }
        }
        // If all retries failed, return error response
        return {
            success: false,
            message: lastError?.message || 'Network request failed after retries',
            error_code: 'NETWORK_ERROR',
            timestamp: new Date().toISOString(),
        };
    }
    /**
     * GET request
     */
    async get(endpoint, includeAuth = true) {
        const url = `${this.baseUrl}${endpoint}`;
        return this.withRetry(() => fetch(url, {
            method: 'GET',
            headers: this.createHeaders(includeAuth),
        }));
    }
    /**
     * POST request
     */
    async post(endpoint, data, includeAuth = true) {
        const url = `${this.baseUrl}${endpoint}`;
        return this.withRetry(() => fetch(url, {
            method: 'POST',
            headers: this.createHeaders(includeAuth),
            body: data ? JSON.stringify(data) : undefined,
        }));
    }
    /**
     * PUT request
     */
    async put(endpoint, data, includeAuth = true) {
        const url = `${this.baseUrl}${endpoint}`;
        return this.withRetry(() => fetch(url, {
            method: 'PUT',
            headers: this.createHeaders(includeAuth),
            body: data ? JSON.stringify(data) : undefined,
        }));
    }
    /**
     * DELETE request
     */
    async delete(endpoint, includeAuth = true) {
        const url = `${this.baseUrl}${endpoint}`;
        return this.withRetry(() => fetch(url, {
            method: 'DELETE',
            headers: this.createHeaders(includeAuth),
        }));
    }
    /**
     * Handle authentication errors by attempting token refresh
     */
    async handleAuthError() {
        try {
            const refreshToken = localStorage.getItem('refresh_token');
            if (!refreshToken) {
                return false;
            }
            const response = await this.post('/api/v1/auth/refresh', { refresh_token: refreshToken }, false // Don't include auth for refresh
            );
            if (response.success && response.data) {
                this.setAuthToken(response.data.access_token);
                localStorage.setItem('refresh_token', response.data.refresh_token);
                return true;
            }
            return false;
        }
        catch (error) {
            console.error('Token refresh failed:', error);
            return false;
        }
    }
    /**
     * Make authenticated request with automatic token refresh
     */
    async authenticatedRequest(method, endpoint, data) {
        let response;
        // Make initial request
        switch (method) {
            case 'GET':
                response = await this.get(endpoint);
                break;
            case 'POST':
                response = await this.post(endpoint, data);
                break;
            case 'PUT':
                response = await this.put(endpoint, data);
                break;
            case 'DELETE':
                response = await this.delete(endpoint);
                break;
        }
        // If unauthorized, try to refresh token and retry once
        if (!response.success && response.error_code === 'HTTP_401') {
            const refreshed = await this.handleAuthError();
            if (refreshed) {
                // Retry the original request
                switch (method) {
                    case 'GET':
                        response = await this.get(endpoint);
                        break;
                    case 'POST':
                        response = await this.post(endpoint, data);
                        break;
                    case 'PUT':
                        response = await this.put(endpoint, data);
                        break;
                    case 'DELETE':
                        response = await this.delete(endpoint);
                        break;
                }
            }
            else {
                // Clear tokens and redirect to login
                this.clearAuthToken();
                localStorage.removeItem('refresh_token');
                // Dispatch custom event for auth failure
                window.dispatchEvent(new CustomEvent('auth:logout', {
                    detail: { reason: 'token_refresh_failed' }
                }));
            }
        }
        return response;
    }
}
// Create singleton instance
export const apiClient = new ApiClient();
